import collections

def edmonds_karp(graph, capacity, source, sink):
    max_flow = 0

    while True:
        parent = {}
        flow_on_path = {}

        queue = collections.deque()
        queue.append(source)
        parent[source] = None
        flow_on_path[source] = float('inf')

        path_found = False
        while queue:
            u = queue.popleft()

            for v in graph[u]:
                if v not in parent and capacity[u][v] > 0:
                    parent[v] = u
                    flow_on_path[v] = min(flow_on_path[u], capacity[u][v])

                    if v == sink:
                        path_found = True
                        break

                    queue.append(v)

            if path_found:
                break

        if not path_found:
            break

        current_path_flow = flow_on_path[sink]
        max_flow += current_path_flow

        current_node = sink
        while current_node != source:
            prev_node = parent[current_node]
            capacity[prev_node][current_node] -= current_path_flow
            capacity[current_node][prev_node] += current_path_flow
            current_node = prev_node

    return max_flow
